# pytest Tests: Procedure Tied to Encounter with AuditEvent Verification

```python
"""
Test Suite: Procedure tied to Encounter with AuditEvent emission
Requirement: A clinician shall record a Procedure tied to an Encounter.
             An AuditEvent must be emitted for every operation and tested end-to-end.

Standards: FHIR R4
"""

import uuid
import pytest
import requests
from datetime import datetime, timezone
from typing import Generator

# ---------------------------------------------------------------------------
# Configuration
# ---------------------------------------------------------------------------

BASE_URL = "http://localhost:8080/fhir"  # override via env / fixture
HEADERS = {
    "Content-Type": "application/fhir+json",
    "Accept": "application/fhir+json",
}

CLINICIAN_HEADERS = {
    **HEADERS,
    "X-User-Id": "practitioner-001",
    "X-User-Role": "clinician",
}


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def fhir_url(resource_type: str, resource_id: str = "") -> str:
    path = f"{BASE_URL}/{resource_type}"
    return f"{path}/{resource_id}" if resource_id else path


def assert_fhir_success(response: requests.Response, expected_status: int = 201) -> dict:
    assert response.status_code == expected_status, (
        f"Expected HTTP {expected_status}, got {response.status_code}. "
        f"Body: {response.text}"
    )
    body = response.json()
    assert "resourceType" in body, "Response is not a FHIR resource"
    return body


def poll_audit_events(
    entity_what_reference: str,
    action: str | None = None,
    timeout_seconds: int = 10,
) -> list[dict]:
    """Poll AuditEvent endpoint until at least one matching event appears."""
    import time

    deadline = time.time() + timeout_seconds
    params = {"entity-what": entity_what_reference}
    if action:
        params["action"] = action

    while time.time() < deadline:
        resp = requests.get(fhir_url("AuditEvent"), headers=HEADERS, params=params)
        assert resp.status_code == 200, f"AuditEvent search failed: {resp.text}"
        bundle = resp.json()
        entries = bundle.get("entry", [])
        if entries:
            return [e["resource"] for e in entries]
        time.sleep(0.5)

    return []


# ---------------------------------------------------------------------------
# Fixtures
# ---------------------------------------------------------------------------

@pytest.fixture(scope="module")
def patient_id() -> Generator[str, None, None]:
    """Create a minimal Patient and yield its logical ID."""
    payload = {
        "resourceType": "Patient",
        "id": str(uuid.uuid4()),
        "name": [{"use": "official", "family": "TestPatient", "given": ["Jane"]}],
        "gender": "female",
        "birthDate": "1990-01-15",
    }
    resp = requests.post(fhir_url("Patient"), json=payload, headers=CLINICIAN_HEADERS)
    resource = assert_fhir_success(resp, 201)
    yield resource["id"]


@pytest.fixture(scope="module")
def practitioner_id() -> Generator[str, None, None]:
    """Create a Practitioner representing the clinician."""
    payload = {
        "resourceType": "Practitioner",
        "id": str(uuid.uuid4()),
        "name": [{"use": "official", "family": "DrSmith", "given": ["Alice"]}],
        "qualification": [
            {
                "code": {
                    "coding": [
                        {
                            "system": "http://terminology.hl7.org/CodeSystem/v2-0360",
                            "code": "MD",
                        }
                    ]
                }
            }
        ],
    }
    resp = requests.post(
        fhir_url("Practitioner"), json=payload, headers=CLINICIAN_HEADERS
    )
    resource = assert_fhir_success(resp, 201)
    yield resource["id"]


@pytest.fixture()
def encounter(patient_id: str, practitioner_id: str) -> dict:
    """Create a fresh Encounter for each test that needs one."""
    payload = {
        "resourceType": "Encounter",
        "status": "in-progress",
        "class": {
            "system": "http://terminology.hl7.org/CodeSystem/v3-ActCode",
            "code": "AMB",
            "display": "ambulatory",
        },
        "subject": {"reference": f"Patient/{patient_id}"},
        "participant": [
            {
                "individual": {"reference": f"Practitioner/{practitioner_id}"}
            }
        ],
        "period": {"start": datetime.now(timezone.utc).isoformat()},
    }
    resp = requests.post(fhir_url("Encounter"), json=payload, headers=CLINICIAN_HEADERS)
    return assert_fhir_success(resp, 201)


@pytest.fixture()
def completed_encounter(encounter: dict) -> dict:
    """Transition an existing Encounter to 'finished' status."""
    encounter_id = encounter["id"]
    encounter["status"] = "finished"
    encounter["period"]["end"] = datetime.now(timezone.utc).isoformat()
    resp = requests.put(
        fhir_url("Encounter", encounter_id),
        json=encounter,
        headers=CLINICIAN_HEADERS,
    )
    return assert_fhir_success(resp, 200)


# ---------------------------------------------------------------------------
# Test Class: Encounter Lifecycle
# ---------------------------------------------------------------------------

class TestEncounterLifecycle:
    """Validate that an Encounter can be created and managed by a clinician."""

    def test_create_encounter_returns_201(self, encounter: dict):
        assert encounter["resourceType"] == "Encounter"
        assert "id" in encounter

    def test_encounter_has_correct_status(self, encounter: dict):
        assert encounter["status"] == "in-progress"

    def test_encounter_references_patient(self, encounter: dict, patient_id: str):
        subject_ref = encounter["subject"]["reference"]
        assert subject_ref == f"Patient/{patient_id}"

    def test_encounter_references_practitioner(
        self, encounter: dict, practitioner_id: str
    ):
        participants = encounter.get("participant", [])
        refs = [p["individual"]["reference"] for p in participants if "individual" in p]
        assert f"Practitioner/{practitioner_id}" in refs

    def test_encounter_finish_updates_status(self, completed_encounter: dict):
        assert completed_encounter["status"] == "finished"

    def test_encounter_finish_sets_end_period(self, completed_encounter: dict):
        assert "end" in completed_encounter.get("period", {})


# ---------------------------------------------------------------------------
# Test Class: Procedure Tied to Encounter
# ---------------------------------------------------------------------------

class TestProcedureTiedToEncounter:
    """Core requirement: a clinician records a Procedure linked to an Encounter."""

    @pytest.fixture()
    def procedure_payload(self, patient_id: str, encounter: dict) -> dict:
        return {
            "resourceType": "Procedure",
            "status": "completed",
            "subject": {"reference": f"Patient/{patient_id}"},
            "encounter": {"reference": f"Encounter/{encounter['id']}"},
            "code": {
                "coding": [
                    {
                        "system": "http://snomed.info/sct",
                        "code": "80146002",
                        "display": "Appendectomy",
                    }
                ],
                "text": "Appendectomy",
            },
            "performedDateTime": datetime.now(timezone.utc).isoformat(),
            "recorder": {"reference": "Practitioner/practitioner-001"},
            "note": [{"text": "Procedure completed without complications."}],
        }

    @pytest.fixture()
    def created_procedure(self, procedure_payload: dict) -> dict:
        resp = requests.post(
            fhir_url("Procedure"), json=procedure_payload, headers=CLINICIAN_HEADERS
        )
        return assert_fhir_success(resp, 201)

    # --- Structural validation ---

    def test_create_procedure_returns_201(self, created_procedure: dict):
        assert created_procedure["resourceType"] == "Procedure"
        assert "id" in created_procedure

    def test_procedure_status_is_completed(self, created_procedure: dict):
        assert created_procedure["status"] == "completed"

    def test_procedure_references_correct_patient(
        self, created_procedure: dict, patient_id: str
    ):
        assert created_procedure["subject"]["reference"] == f"Patient/{patient_id}"

    def test_procedure_references_encounter(
        self, created_procedure: dict, encounter: dict
    ):
        enc_ref = created_procedure.get("encounter", {}).get("reference", "")
        assert enc_ref == f"Encounter/{encounter['id']}", (
            "Procedure must be tied to the Encounter"
        )

    def test_procedure_has_snomed_code(self, created_procedure: dict):
        codings = created_procedure["code"]["coding"]
        systems = [c["system"] for c in codings]
        assert "http://snomed.info/sct" in systems

    def test_procedure_has_performed_date(self, created_procedure: dict):
        assert "performedDateTime" in created_procedure or "performedPeriod" in created_procedure

    def test_procedure_has_recorder(self, created_procedure: dict):
        assert "recorder" in created_procedure

    # --- Retrieval validation ---

    def test_read_procedure_by_id(self, created_procedure: dict):
        proc_id = created_procedure["id"]
        resp = requests.get(fhir_url("Procedure", proc_id), headers=HEADERS)
        fetched = assert_fhir_success(resp, 200)
        assert fetched["id"] == proc_id

    def test_search_procedure_by_encounter(
        self, created_procedure: dict, encounter: dict
    ):
        resp = requests.get(
            fhir_url("Procedure"),
            headers=HEADERS,
            params={"encounter": f"Encounter/{encounter['id']}"},
        )
        bundle = assert_fhir_success(resp, 200)
        ids = [e["resource"]["id"] for e in bundle.get("entry", [])]
        assert created_procedure["id"] in ids

    def test_search_procedure_by_patient(
        self, created_procedure: dict, patient_id: str
    ):
        resp = requests.get(
            fhir_url("Procedure"),
            headers=HEADERS,
            params={"patient": patient_id},
        )
        bundle = assert_fhir_success(resp, 200)
        ids = [e["resource"]["id"] for e in bundle.get("entry", [])]
        assert created_procedure["id"] in ids

    # --- Integrity constraints ---

    def test_procedure_without_encounter_is_rejected(
        self, procedure_payload: dict
    ):
        """Business rule: Procedure MUST reference an Encounter."""
        del procedure_payload["encounter"]
        resp = requests.post(
            fhir_url("Procedure"), json=procedure_payload, headers=CLINICIAN_HEADERS
        )
        assert resp.status_code in (400, 422), (
            "Server must reject a Procedure that has no Encounter reference"
        )

    def test_procedure_with_nonexistent_encounter_is_rejected(
        self, procedure_payload: dict
    ):
        procedure_payload["encounter"] = {"reference": "Encounter/does-not-exist-999"}
        resp = requests.post(
            fhir_url("Procedure"), json=procedure_payload, headers=CLINICIAN_HEADERS
        )
        assert resp.status_code in (400, 404, 422), (
            "Server must reject a Procedure referencing a non-existent Encounter"
        )

    def test_procedure_with_invalid_status_is_rejected(
        self, procedure_payload: dict
    ):
        procedure_payload["status"] = "banana"
        resp = requests.post(
            fhir_url("Procedure"), json=procedure_payload, headers=CLINICIAN_HEADERS
        )
        assert resp.status_code in (400, 422)

    def test_unauthenticated_procedure_creation_is_rejected(
        self, procedure_payload: dict
    ):
        resp = requests.post(
            fhir_url("Procedure"), json=procedure_payload, headers=HEADERS
        )
        assert resp.status_code in (401, 403)

    # --- Update / Delete ---

    def test_update_procedure_note(self, created_procedure: dict):
        proc_id = created_procedure["id"]
        created_procedure["note"] = [{"text": "Updated: minor complication noted."}]
        resp = requests.put(
            fhir_url("Procedure", proc_id),
            json=created_procedure,
            headers=CLINICIAN_HEADERS,
        )
        updated = assert_fhir_success(resp, 200)
        assert updated["note"][0]["text"] == "Updated: minor complication noted."

    def test_delete_procedure(self, procedure_payload: dict):
        resp = requests.post(
            fhir_url("Procedure"), json=procedure_payload, headers=CLINICIAN_HEADERS
        )
        resource = assert_fhir_success(resp, 201)
        proc_id = resource["id"]

        del_resp = requests.delete(
            fhir_url("Procedure", proc_id), headers=CLINICIAN_HEADERS
        )
        assert del_resp.status_code == 204, f"Expected 204 on delete, got {del_resp.status_code}"

        get_resp = requests.get(fhir_url("Procedure", proc_id), headers=HEADERS)
        assert get_resp.status_code == 410, "Deleted resource should return 410 Gone"


# ---------------------------------------------------------------------------
# Test Class: AuditEvent Emission (End-to-End)
# ---------------------------------------------------------------------------

class TestAuditEventEndToEnd:
    """
    Validate that every operation (C/R/U/D) on Procedure and Encounter
    emits a conformant AuditEvent.
    """

    @pytest.fixture()
    def procedure_for_audit(self, patient_id: str, encounter: dict) -> dict:
        payload = {
            "resourceType": "Procedure",
            "status": "completed",
            "subject": {"reference": f"Patient/{patient_id}"},
            "encounter": {"reference": f"Encounter/{encounter['id']}"},
            "code": {
                "coding": [
                    {
                        "system": "http://snomed.info/sct",
                        "code": "174432009",
                        "display": "Total hip replacement",
                    }
                ]
            },
            "performedDateTime": datetime.now(timezone.utc).isoformat(),
        }
        resp = requests.post(
            fhir_url("Procedure"), json=payload, headers=CLINICIAN_HEADERS
        )
        return assert_fhir_success(resp, 201)

    # --- Encounter AuditEvents ---

    def test_audit_event_emitted_for_encounter_create(self, encounter: dict):
        enc_ref = f"Encounter/{encounter['id']}"
        events = poll_audit_events(enc_ref, action="C")
        assert events, f"No AuditEvent(action=C) found for {enc_ref}"

    def test_audit_event_emitted_for_encounter_read(self, encounter: dict):
        enc_id = encounter["id"]
        requests.get(fhir_url("Encounter", enc_id), headers=CLINICIAN_HEADERS)
        enc_ref = f"Encounter/{enc_id}"
        events = poll_audit_events(enc_ref, action="R")
        assert events, f"No AuditEvent(action=R) found for {enc_ref}"

    def test_audit_event_emitted_for_encounter_update(
        self, encounter: dict, completed_encounter: dict
    ):
        enc_ref = f"Encounter/{encounter['id']}"
        events = poll_audit_events(enc_ref, action="U")
        assert events, f"No AuditEvent(action=U) found for {enc_ref}"

    # --- Procedure AuditEvents ---

    def test_audit_event_emitted_for_procedure_create(
        self, procedure_for_audit: dict
    ):
        proc_ref = f"Procedure/{procedure_for_audit['id']}"
        events = poll_audit_events(proc_ref, action="C")
        assert events, f"No AuditEvent(action=C) found for {proc_ref}"

    def test_audit_event_emitted_for_procedure_read(
        self, procedure_for_audit: dict
    ):
        proc_id = procedure_for_audit["id"]
        requests.get(fhir_url("Procedure", proc_id), headers=CLINICIAN_HEADERS)
        proc_ref = f"Procedure/{proc_id}"
        events = poll_audit_events(proc_ref, action="R")
        assert events, f"No AuditEvent(action=R) found for {proc_ref}"

    def test_audit_event_emitted_for_procedure_update(
        self, procedure_for_audit: dict
    ):
        proc_id = procedure_for_audit["id"]
        procedure_for_audit["status"] = "entered-in-error"
        requests.put(
            fhir_url("Procedure", proc_id),
            json=procedure_for_audit,
            headers=CLINICIAN_HEADERS,
        )
        proc_ref = f"Procedure/{proc_id}"
        events = poll_audit_events(proc_ref, action="U")
        assert events, f"No AuditEvent(action=U) found for {proc_ref}"

    def test_audit_event_emitted_for_procedure_delete(
        self, patient_id: str, encounter: dict
    ):
        payload = {
            "resourceType": "Procedure",
            "status": "completed",
            "subject": {"reference": f"Patient/{patient_id}"},
            "encounter": {"reference": f"Encounter/{encounter['id']}"},
            "code": {"text": "Temp procedure for delete audit test"},
            "performedDateTime": datetime.now(timezone.utc).isoformat(),
        }
        resp = requests.post(
            fhir_url("Procedure"), json=payload, headers=CLINICIAN_HEADERS
        )
        resource = assert_fhir_success(resp, 201)
        proc_id = resource["id"]

        requests.delete(fhir_url("Procedure", proc_id), headers=CLINICIAN_HEADERS)

        proc_ref = f"Procedure/{proc_id}"
        events = poll_audit_events(proc_ref, action="D")
        assert events, f"No AuditEvent(action=D) found for {proc_ref}"

    # --- AuditEvent structure validation ---

    def test_audit_event_has_required_fields(self, procedure_for_audit: dict):
        proc_ref = f"Procedure/{procedure_for_audit['id']}"
        events = poll_audit_events(proc_ref, action="C")
        assert events, "No AuditEvent found for structure validation"
        event = events[0]

        assert event["resourceType"] == "AuditEvent"
        assert "type" in event, "AuditEvent must have 'type'"
        assert "recorded" in event, "AuditEvent must have 'recorded' timestamp"
        assert "agent" in event, "AuditEvent must have at least one 'agent'"
        assert "source" in event, "AuditEvent must have 'source'"
        assert "entity" in event, "AuditEvent must have 'entity'"

    def test_audit_event_agent_identifies_clinician(
        self, procedure_for_audit: dict
    ):
        proc_ref = f"Procedure/{procedure_for_audit['id']}"
        events = poll_audit_events(proc_ref, action="C")
        assert events
        event = events[0]
        agent_refs = [
            a.get("who", {}).get("reference", "") for a in event.get("agent", [])
        ]
        assert any("practitioner" in ref.lower() or "001" in ref for ref in agent_refs), (
            f"AuditEvent agent should identify the clinician. Agents: {agent_refs}"
        )

    def test_audit_event_entity_references_procedure(
        self, procedure_for_audit: dict
    ):
        proc_id = procedure_for_audit["id"]
        proc_ref = f"Procedure/{proc_id}"
        events = poll_audit_events(proc_ref, action="C")
        assert events
        event = events[0]
        entity_refs = [
            e.get("what", {}).get("reference", "") for e in event.get("entity", [])
        ]
        assert any(proc_id in ref for ref in entity_refs), (
            f"AuditEvent entity must reference the Procedure. Entities: {entity_refs}"
        )

    def test_audit_event_recorded_timestamp_is_recent(
        self, procedure_for_audit: dict
    ):
        proc_ref = f"Procedure/{procedure_for_audit['id']}"
        events = poll_audit_events(proc_ref, action="C")
        assert events
        recorded_str = events[0]["recorded"]
        recorded_dt = datetime.fromisoformat(recorded_str.replace("Z", "+00:00"))
        now = datetime.now(timezone.utc)
        delta_seconds = abs((now - recorded_dt).total_seconds())
        assert delta_seconds < 300, (
            f"AuditEvent.recorded ({recorded_str}) is not within 5 minutes of now"
        )

    def test_audit_event_action_code_matches_operation(
        self, procedure_for_audit: dict
    ):
        proc_ref = f"Procedure/{procedure_for_audit['id']}"
        events = poll_audit_events(proc_ref, action="C")
        assert events
        assert events[0].get("action") == "C", (
            "AuditEvent action must be 'C' (Create) for a POST operation"
        )

    def test_audit_event_outcome_is_success(self, procedure_for_audit: dict):
        proc_ref = f"Procedure/{procedure_for_audit['id']}"
        events = poll_audit_events(proc_ref, action="C")
        assert events
        # FHIR AuditEvent.outcome: 0 = success
        assert events[0].get("outcome", "0") == "0", (
            "AuditEvent.outcome must be '0' (success) for a valid operation"
        )

    def test_failed_operation_emits_audit_event_with_failure_outcome(
        self, patient_id: str, encounter: dict
    ):
        """A rejected Procedure creation must still produce an AuditEvent with failure outcome."""
        bad_payload = {
            "resourceType": "Procedure",
            "status": "invalid-status",
            "subject": {"reference": f"Patient/{patient_id}"},
            "encounter": {"reference": f"Encounter/{encounter['id']}"},
            "code": {"text": "Should fail"},
        }
        resp = requests.post(
            fhir_url("Procedure"), json=bad_payload, headers=CLINICIAN_HEADERS
        )
        assert resp.status_code in (400, 422)

        # AuditEvents for failed attempts use a correlation header or OperationOutcome id
        # Here we search broadly for recent failure events
        params = {"outcome": "8", "_sort": "-date", "_count": "5"}
        audit_resp = requests.get(
            fhir_url("AuditEvent"), headers=HEADERS, params=params
        )
        assert audit_resp.status_code == 200
        bundle = audit_resp.json()
        entries = bundle.get("entry", [])
        assert entries, "At least one failure AuditEvent must be emitted for rejected operations"

    # --- No duplicate AuditEvents ---

    def test_single_create_emits_exactly_one_audit_event(
        self, patient_id: str, encounter: dict
    ):
        unique_note = str(uuid.uuid4())
        payload = {
            "resourceType": "Procedure",
            "status": "completed",
            "subject": {"reference": f"Patient/{patient_id}"},
            "encounter": {"reference": f"Encounter/{encounter['id']}"},
            "code": {"text": unique_note},
            "performedDateTime": datetime.now(timezone.utc).isoformat(),
        }
        resp = requests.post(
            fhir_url("Procedure"), json=payload, headers=CLINICIAN_HEADERS
        )
        resource = assert_fhir_success(resp, 201)
        proc_ref = f"Procedure/{resource['id']}"

        events = poll_audit_events(proc_ref, action="C")
        assert len(events) == 1, (
            f"Exactly 1 Create AuditEvent expected, got {len(events)}"
        )
```

---

## Design Notes

| Concern | Approach |
|---|---|
| **Fixture scoping** | `patient_id` / `practitioner_id` are `module`-scoped (created once); `encounter` and procedures are function-scoped (fresh per test) to avoid state leakage |
| **AuditEvent polling** | `poll_audit_events()` retries for up to 10 s to handle async emitters |
| **FHIR action codes** | `C` Create · `R` Read · `U` Update · `D` Delete per FHIR AuditEvent spec |
| **Failure path audit** | Verifies that *rejected* operations also produce an AuditEvent (outcome ≠ 0) |
| **Duplicate guard** | One CREATE → exactly one AuditEvent with `action=C` |
| **Auth enforcement** | Unauthenticated requests must be 401/403 |
| **Referential integrity** | Missing or non-existent Encounter reference must be rejected (400/422) |

